-- ============================================================
-- Ephemera Knowledge Graph (exported from graphify)
-- Compatible with SQLite, PostgreSQL, MySQL, SQL Server
-- Generated: 2026-06-12 21:43:46
-- Nodes: 2079 | Edges: 5163 | Communities: 92
-- ============================================================

BEGIN TRANSACTION;

-- Community labels (knowledge groups)
CREATE TABLE IF NOT EXISTS communities (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL
);

-- Nodes (symbols, files, concepts)
CREATE TABLE IF NOT EXISTS nodes (
    id TEXT PRIMARY KEY,
    label TEXT NOT NULL,
    norm_label TEXT,
    file_type TEXT,
    source_file TEXT,
    source_location TEXT,
    origin TEXT,
    community_id INTEGER,
    FOREIGN KEY (community_id) REFERENCES communities(id)
);

-- Edges (relationships between nodes)
CREATE TABLE IF NOT EXISTS edges (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    source TEXT NOT NULL,
    target TEXT NOT NULL,
    relation TEXT NOT NULL,
    confidence TEXT,
    confidence_score REAL,
    weight REAL DEFAULT 1.0,
    source_file TEXT,
    source_location TEXT,
    FOREIGN KEY (source) REFERENCES nodes(id),
    FOREIGN KEY (target) REFERENCES nodes(id)
);

-- Hyperedges (group-level relationships)
CREATE TABLE IF NOT EXISTS hyperedges (
    id TEXT PRIMARY KEY,
    label TEXT,
    relation TEXT,
    confidence TEXT,
    confidence_score REAL,
    source_file TEXT
);

-- Junction table: hyperedge -> node membership
CREATE TABLE IF NOT EXISTS hyperedge_nodes (
    hyperedge_id TEXT NOT NULL,
    node_id TEXT NOT NULL,
    PRIMARY KEY (hyperedge_id, node_id),
    FOREIGN KEY (hyperedge_id) REFERENCES hyperedges(id),
    FOREIGN KEY (node_id) REFERENCES nodes(id)
);

-- Indexes for fast lookup
CREATE INDEX IF NOT EXISTS idx_nodes_community ON nodes(community_id);
CREATE INDEX IF NOT EXISTS idx_nodes_source ON nodes(source_file);
CREATE INDEX IF NOT EXISTS idx_edges_source ON edges(source);
CREATE INDEX IF NOT EXISTS idx_edges_target ON edges(target);
CREATE INDEX IF NOT EXISTS idx_edges_relation ON edges(relation);
CREATE INDEX IF NOT EXISTS idx_hyperedge_nodes_node ON hyperedge_nodes(node_id);

